# CHOP Execute DAT callback — fires when OSC values change
def onValueChange(channel, sampleIndex, val, prev):
    # React to a specific OSC address
    if channel.name == '/button1' and val == 1.0:
        # Trigger a scene change
        op('/project1/scene_switch').par.index = 1
        print('Scene 1 activated via OSC')

    elif channel.name == '/fader1':
        # Map fader to opacity
        op('/project1/level1').par.opacity = val
